#!/usr/bin/env python3
"""
Bug #0042: jax.jit produces wrong output vs jax.disable_jit.

Patterns    : [['layout', 'row_reduce_mul_transpose'], ['fusion', 'mul_add_mul_chain'], ['normalization', 'reduce_max_last'], ['normalization', 'layernorm_residual_add'], ['branch', 'add_layernorm'], ['branch', 'add_relu_sub']]
Dependencies: numpy jax
Run         : python unique_0042.py  →  exit 0 = BUG REPRODUCED
"""
import sys
import numpy as np
import jax, jax.numpy as jnp
from jax import lax
import jax.scipy.special

# ── Model weights ─────────────────────────────────────────────────────────────
_w0 = np.frombuffer(bytes.fromhex("9a99993f"), dtype=np.float32).reshape([1])
_w1 = np.frombuffer(bytes.fromhex("9a99993e"), dtype=np.float32).reshape([1])
_w2 = np.frombuffer(bytes.fromhex("0000c03f"), dtype=np.float32).reshape([1])
_w3 = np.frombuffer(bytes.fromhex("00000000"), dtype=np.float32).reshape([1])
_w4 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([256])
_w5 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([256])
_w6 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 16, 256])
_w7 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 16, 256])
_w8 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([256])
_w9 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([256])

# ── Triggering input ─────────────────────────────────────────────────────────
INPUT = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 16, 256])  # input "model_input"


# ── Model computation (translated from ONNX) ──────────────────────────────────
def model(x):
    n0_rrmt_mean = jnp.mean(x, axis=(-1,), keepdims=True)
    n0_rrmt_sub = x - n0_rrmt_mean
    n0_rrmt_scl = n0_rrmt_sub * n0_rrmt_sub
    n0_rrmt_tp = jnp.transpose(n0_rrmt_scl, [0, 2, 1])
    n0_rrmt_out = jnp.transpose(n0_rrmt_tp, [0, 2, 1])
    n100_mam_x1 = n0_rrmt_out * _w0
    n100_mam_x2 = n100_mam_x1 + _w1
    n100_mam_out = n100_mam_x2 * _w2
    n200_redu_red = jnp.max(n100_mam_out, axis=(-1,), keepdims=True)
    n200_redu_z = n100_mam_out * _w3
    n200_redu_out = n200_redu_z + n200_redu_red
    n300_lnradd_ln = (((lambda _x: (lambda _m, _v: (_x - _m) / jnp.sqrt(_v + np.float32(9.999999747378752e-06)))(jnp.mean(_x, axis=tuple(range(-1%_x.ndim, _x.ndim)), keepdims=True), jnp.mean((_x - jnp.mean(_x, axis=tuple(range(-1%_x.ndim, _x.ndim)), keepdims=True))**2, axis=tuple(range(-1%_x.ndim, _x.ndim)), keepdims=True)))(n200_redu_out)) * _w4) + _w5
    n300_lnradd_out = n300_lnradd_ln + _w6
    n400_aln_add = n300_lnradd_out + _w7
    n400_aln_out = (((lambda _x: (lambda _m, _v: (_x - _m) / jnp.sqrt(_v + np.float32(9.999999747378752e-06)))(jnp.mean(_x, axis=tuple(range(-1%_x.ndim, _x.ndim)), keepdims=True), jnp.mean((_x - jnp.mean(_x, axis=tuple(range(-1%_x.ndim, _x.ndim)), keepdims=True))**2, axis=tuple(range(-1%_x.ndim, _x.ndim)), keepdims=True)))(n400_aln_add)) * _w8) + _w9
    n500_ars_ad = n400_aln_out + n400_aln_out
    n500_ars_rl = jnp.maximum(n500_ars_ad, np.float32(0.0))
    n500_ars_out = n500_ars_rl - n400_aln_out
    return jnp.asarray(n500_ars_out, dtype=jnp.float32)


if __name__ == "__main__":
    x_jax = jnp.array(INPUT)

    with jax.disable_jit():
        ref = np.array(model(x_jax), dtype=np.float32).ravel()

    out = np.array(jax.jit(model)(x_jax), dtype=np.float32).ravel()

    diff = float(np.linalg.norm(ref.astype(np.float64) - out.astype(np.float64))
                 / (np.linalg.norm(ref.astype(np.float64)) + 1e-8))
    print(f"expected (jax.disable_jit): {ref[:6]}")
    print(f"actual   (jax.jit)        : {out[:6]}")
    print(f"rel L2 : {diff:.4e}")
    if diff > 0.001:
        print("BUG REPRODUCED")
        sys.exit(0)
    sys.exit(1)
